document.addEventListener('DOMContentLoaded',function(){console.log("Blog JS initialized.");console.log("Share buttons found:",document.querySelectorAll('.action-share').length);const shareBtn=document.querySelector('.action-share');if(shareBtn){console.log("Share button visibility:",getComputedStyle(shareBtn).visibility);console.log("Share button display:",getComputedStyle(shareBtn).display);console.log("Share button opacity:",getComputedStyle(shareBtn).opacity);}
document.querySelectorAll('.like-btn').forEach(btn=>{const postId=btn.getAttribute('data-id');if(document.cookie.includes(`liked_post_${postId}=`)){const icon=btn.querySelector('i');if(icon)icon.classList.replace('fa-regular','fa-solid');btn.style.color="#e74c3c";btn.classList.add('voted');}});document.querySelectorAll('.action-share').forEach(btn=>{const postId=btn.getAttribute('data-id');if(document.cookie.includes(`shared_post_${postId}=`)){btn.classList.add('shared');}});});document.addEventListener('click',function(event){const btn=event.target.closest('.like-btn');if(btn){event.preventDefault();event.stopPropagation();const postId=btn.getAttribute('data-id');const countSpan=btn.querySelector('.count');const icon=btn.querySelector('i');console.log("Attempting like for ID:",postId);const wasLiked=btn.classList.contains('voted');const currentCount=parseInt(countSpan.innerText,10);if(wasLiked){countSpan.innerText=currentCount-1;if(icon)icon.classList.replace('fa-solid','fa-regular');btn.style.color="";btn.classList.remove('voted');}else{countSpan.innerText=currentCount+1;if(icon)icon.classList.replace('fa-regular','fa-solid');btn.style.color="#e74c3c";btn.classList.add('voted');}
btn.disabled=true;fetch('/like/'+postId,{method:'POST',headers:{'Content-Type':'application/json'}}).then(response=>response.json()).then(data=>{console.log("Server Response:",data);if(data.success===true){document.querySelectorAll(`.like-btn[data-id="${postId}"].count`).forEach(span=>span.innerText=data.new_count);if(data.liked===true){document.querySelectorAll(`.like-btn[data-id="${postId}"]`).forEach(b=>{const i=b.querySelector('i');if(i)i.classList.replace('fa-regular','fa-solid');b.style.color="#e74c3c";b.classList.add('voted');});if(typeof gtag==='function'){gtag('event','blog_like',{'post_id':postId,'action':'like'});}}else{document.querySelectorAll(`.like-btn[data-id="${postId}"]`).forEach(b=>{const i=b.querySelector('i');if(i)i.classList.replace('fa-solid','fa-regular');b.style.color="";b.classList.remove('voted');});if(typeof gtag==='function'){gtag('event','blog_like',{'post_id':postId,'action':'unlike'});}}}
btn.disabled=false;if(data.success===false){console.log("Like failed: "+data.message);if(wasLiked){countSpan.innerText=currentCount;if(icon)icon.classList.replace('fa-regular','fa-solid');btn.style.color="#e74c3c";btn.classList.add('voted');}else{countSpan.innerText=currentCount;if(icon)icon.classList.replace('fa-solid','fa-regular');btn.style.color="";btn.classList.remove('voted');}}}).catch(error=>{console.error("Fetch Error:",error);if(wasLiked){countSpan.innerText=currentCount;if(icon)icon.classList.replace('fa-regular','fa-solid');btn.style.color="#e74c3c";btn.classList.add('voted');}else{countSpan.innerText=currentCount;if(icon)icon.classList.replace('fa-solid','fa-regular');btn.style.color="";btn.classList.remove('voted');}
btn.disabled=false;});}
const shareBtn=event.target.closest('.action-share');if(shareBtn){event.preventDefault();const postId=shareBtn.getAttribute('data-id');const countSpan=shareBtn.querySelector('.count');console.log("Attempting share for ID:",postId);const currentCount=parseInt(countSpan.innerText,10);const alreadyShared=shareBtn.classList.contains('shared');if(!alreadyShared){countSpan.innerText=currentCount+1;shareBtn.classList.add('shared');}
shareBtn.disabled=true;fetch('/share/'+postId,{method:'POST',headers:{'Content-Type':'application/json'}}).then(response=>response.json()).then(data=>{console.log("Share Server Response:",data);if(data.success===true){document.querySelectorAll(`.action-share[data-id="${postId}"].count`).forEach(span=>span.innerText=data.new_count);document.querySelectorAll(`.action-share[data-id="${postId}"]`).forEach(b=>b.classList.add('shared'));if(typeof gtag==='function'){gtag('event','blog_share',{'post_id':postId,'method':'copy_link'});}
const url=window.location.href;navigator.clipboard.writeText(url).then(()=>{const originalContent=shareBtn.innerHTML;shareBtn.innerHTML='<i class="fa-solid fa-check"></i> <span>Copied!</span>';shareBtn.classList.add('share-success');setTimeout(()=>{shareBtn.innerHTML=originalContent;shareBtn.classList.remove('share-success');shareBtn.disabled=false;},2000);}).catch(err=>{console.error('Could not copy text: ',err);});}else{console.log("Share blocked: "+data.message);countSpan.innerText=currentCount;shareBtn.classList.remove('shared');const url=window.location.href;navigator.clipboard.writeText(url).then(()=>{shareBtn.innerHTML='<i class="fa-solid fa-check"></i> <span>Copied!</span>';shareBtn.classList.add('share-success');setTimeout(()=>{shareBtn.innerHTML='<i class="fa-solid fa-share-nodes"></i> <span class="count">'+countSpan.innerText+'</span>';shareBtn.classList.remove('share-success');shareBtn.disabled=false;},2000);});}}).catch(error=>{console.error("Share Fetch Error:",error);countSpan.innerText=currentCount;shareBtn.classList.remove('shared');shareBtn.disabled=false;});}
const commentBtn=event.target.closest('button[title="Comment"]');if(commentBtn){event.preventDefault();console.log("Comment button clicked, attempting to scroll to comments.");const commentsSection=document.getElementById('comments');if(commentsSection){console.log("Comments section found, scrolling.");commentsSection.scrollIntoView({behavior:'smooth'});}else{console.log("Comments section not found.");}}});document.addEventListener('click',function(event){const anchor=event.target.closest('a[href^="#"]');if(anchor){const href=anchor.getAttribute('href');if(href&&href!=='#'){const fullUrl=window.location.origin+window.location.pathname+href;fetch('/log_event?url='+encodeURIComponent(fullUrl)+'&_cb='+Date.now());}}});fetch('/log_event?url='+encodeURIComponent(window.location.href)+'&_cb='+Date.now());